let CurrentTime = now();
let ComplianceData = DeviceInfo
| where Timestamp {TimeRange}
| where OnboardingStatus == 'Onboarded'
| summarize LastSeen = max(Timestamp) by DeviceId, DeviceName
| extend ComplianceStatus = iff(datetime_diff('day', CurrentTime, LastSeen) <= 30, 'Compliant', 'Noncompliant');
let TotalDevices = ComplianceData | summarize count();
let CompliantCount = ComplianceData | where ComplianceStatus == 'Compliant' | summarize count();
ComplianceData
| summarize Total=count(), Compliant=countif(ComplianceStatus=='Compliant')
| extend CompliancePercentage = round((Compliant * 100.0) / Total, 2)
| project CompliancePercentage

let DeviceNameToSearch = '';
let Connections =
DeviceEvents
| where Timestamp {TimeRange}
| where (isempty(DeviceNameToSearch) or DeviceName =~ DeviceNameToSearch)
| where ActionType == 'PnpDeviceConnected'
| extend parsed = parse_json(AdditionalFields)
| project
    DeviceId,
    DeviceName,
    ConnectionTime = Timestamp,
    DeviceClass = tostring(parsed.ClassName),
    UsbDeviceId = tostring(parsed.DeviceId),
    ClassId = tostring(parsed.DeviceId),
    DeviceDescription = tostring(parsed.DeviceDescription),
    VendorIds = tostring(parsed.VendorIds)
| where DeviceClass == 'USB'
| where DeviceDescription == 'USB Mass Storage Device';
let UsbWrites =
DeviceFileEvents
| where Timestamp {TimeRange}
| where (isempty(DeviceNameToSearch) or DeviceName =~ DeviceNameToSearch)
| where FolderPath !startswith 'c'
| where FolderPath !startswith @'\'
| join kind=inner Connections on DeviceId;
let SpanDays =
    toscalar(
        UsbWrites
        | summarize spanDays = todouble(datetime_diff('day', max(Timestamp), min(Timestamp)))
    );
let BinSize = case(
    isnull(SpanDays), 1d,
    SpanDays <= 31, 1d,
    SpanDays <= 120, 2d,
    SpanDays <= 365, 7d,
    SpanDays <= 730, 14d,
    30d
);
UsbWrites
| extend ApprovalStatus = 'USB Write Activity'
| summarize IncidentCount = count() by ['Last Update'] = bin(Timestamp, BinSize), ApprovalStatus
| order by ['Last Update'] asc

let DeviceNameToSearch = '';
let Connections =
DeviceEvents
| where Timestamp {TimeRange}
| where (isempty(DeviceNameToSearch) or DeviceName =~ DeviceNameToSearch) and ActionType == 'PnpDeviceConnected'
| extend parsed = parse_json(AdditionalFields)
| project DeviceId, DeviceName, ConnectionTime = Timestamp, DeviceClass = tostring(parsed.ClassName), UsbDeviceId = tostring(parsed.DeviceId), ClassId = tostring(parsed.DeviceId), DeviceDescription = tostring(parsed.DeviceDescription), VendorIds = tostring(parsed.VendorIds)
| where DeviceClass == 'USB' and DeviceDescription == 'USB Mass Storage Device';
DeviceFileEvents
| where Timestamp {TimeRange}
| where (isempty(DeviceNameToSearch) or DeviceName =~ DeviceNameToSearch) and FolderPath !startswith 'c' and FolderPath !startswith @'\'
| join kind=inner Connections on DeviceId
| top 250 by Timestamp desc
| project ['Last Update']=Timestamp, DeviceName, InitiatingProcessAccountName, DeviceClass, DeviceDescription, FileName

let FWPolicyName = 'FW Policy';
let LatestAssignmentTime = toscalar(
    IntuneAuditLogs
    | where TimeGenerated {TimeRange}
    | extend P = parse_json(Properties)
    | extend PolicyName = tostring(coalesce(P.TargetDisplayNames[0], P.Targets[0].Name, ''))
    | where PolicyName =~ FWPolicyName
    | where OperationName has 'DeviceManagementConfigurationPolicyAssignment'
    | where ResultType == 'Success'
    | summarize LatestAssignment=max(TimeGenerated)
);
let DevicesSynced = toscalar(
    IntuneAuditLogs
    | where isnotnull(LatestAssignmentTime)
    | where TimeGenerated between (LatestAssignmentTime .. LatestAssignmentTime + 24h)
    | where OperationName == 'syncDevice ManagedDevice'
    | extend ManagedDeviceId = tostring(extractjson('$.TargetObjectIds[0]', Properties))
    | where isnotempty(ManagedDeviceId)
    | summarize dcount(ManagedDeviceId)
);
let DevicesCompliance = toscalar(
    IntuneDeviceComplianceOrg
    | where isnotnull(LatestAssignmentTime)
    | where TimeGenerated between (LatestAssignmentTime .. LatestAssignmentTime + 24h)
    | where OperationName == 'DeviceCompliance'
    | where isnotempty(DeviceId)
    | summarize dcount(DeviceId)
);
union
(print Evidence='Successful FW Policy Assignments', Count=iff(isnull(LatestAssignmentTime), 0, 1)),
(print Evidence='Devices Synced in 24h', Count=coalesce(DevicesSynced, 0)),
(print Evidence='Devices with Compliance Check in 24h', Count=coalesce(DevicesCompliance, 0))

let FWPolicyName = 'FW Policy';
let LatestAssignmentTime = toscalar(
    IntuneAuditLogs
    | where TimeGenerated {TimeRange}
    | extend P = parse_json(Properties)
    | extend PolicyName = tostring(coalesce(P.TargetDisplayNames[0], P.Targets[0].Name, ''))
    | where PolicyName =~ FWPolicyName
    | where OperationName has 'DeviceManagementConfigurationPolicyAssignment'
    | where ResultType == 'Success'
    | summarize LatestAssignment=max(TimeGenerated)
);
let DevicesSynced = toscalar(
    IntuneAuditLogs
    | where isnotnull(LatestAssignmentTime)
    | where TimeGenerated between (LatestAssignmentTime .. LatestAssignmentTime + 24h)
    | where OperationName == 'syncDevice ManagedDevice'
    | extend ManagedDeviceId = tostring(extractjson('$.TargetObjectIds[0]', Properties))
    | where isnotempty(ManagedDeviceId)
    | summarize dcount(ManagedDeviceId)
);
let DevicesCompliance = toscalar(
    IntuneDeviceComplianceOrg
    | where isnotnull(LatestAssignmentTime)
    | where TimeGenerated between (LatestAssignmentTime .. LatestAssignmentTime + 24h)
    | where OperationName == 'DeviceCompliance'
    | where isnotempty(DeviceId)
    | summarize dcount(DeviceId)
);
print CompliancePercentage = iff(coalesce(DevicesSynced, 0) == 0, 0.0, round((todouble(coalesce(DevicesCompliance, 0)) * 100.0) / todouble(DevicesSynced), 2))

let FWPolicyName = 'FW Policy';
let StartDay = toscalar(IntuneAuditLogs | where TimeGenerated {TimeRange} | summarize startofday(min(TimeGenerated)));
let EndDay = toscalar(IntuneAuditLogs | where TimeGenerated {TimeRange} | summarize startofday(max(TimeGenerated)));
let DailyActivity = IntuneAuditLogs
| where TimeGenerated {TimeRange}
| extend P = parse_json(Properties)
| extend PolicyName = tostring(coalesce(P.TargetDisplayNames[0], P.Targets[0].Name, ''))
| where PolicyName =~ FWPolicyName
| extend OperationCategory = case(OperationName has 'Assignment', 'Assignment', OperationName has 'Create', 'Create', OperationName has 'Patch', 'Update', 'Other')
| summarize Create = countif(OperationCategory == 'Create'), Assignment = countif(OperationCategory == 'Assignment'), Update = countif(OperationCategory == 'Update') by Day = bin(TimeGenerated, 1d);
range Day from iif(isnull(StartDay), startofday(ago(30d)), StartDay) to iif(isnull(EndDay), startofday(now()), EndDay) step 1d
| join kind=leftouter DailyActivity on Day
| project Timestamp = Day, Create = coalesce(Create, 0), Assignment = coalesce(Assignment, 0), Update = coalesce(Update, 0)
| order by Timestamp asc
